let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  if (typeof rawTags === 'string') {
    if (rawTags.trim() === '') return [];
    return rawTags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
  }
  if (Array.isArray(rawTags)) {
    return rawTags.map(t => t.toLowerCase());
  }
  return [];
}

/**
 * Load problems from JSON file and cache them.
 * @returns {Array<Object>}
 */
function loadProblems() {
  if (cachedProblems) return cachedProblems;
  const filePath = path.resolve(__dirname, '../../data/problems.json');
  const data = fs.readFileSync(filePath, 'utf8');
  cachedProblems = JSON.parse(data);
  return cachedProblems;
}

/**
 * Filter problems by difficulty, tags, and components.
 * @param {Array<Object>} problems
 * @param {Object} filters
 * @param {number} filters.minDifficulty
 * @param {number} filters.maxDifficulty
 * @param {Array<string>} filters.tags
 * @param {Array<string>} filters.components
 * @returns {Array<Object>}
 */
function filterProblems(problems, filters) {
  return problems.filter(p => {
    if (filters.minDifficulty !== undefined && p.difficulty < filters.minDifficulty) return false;
    if (filters.maxDifficulty !== undefined && p.difficulty > filters.maxDifficulty) return false;
    if (filters.tags && filters.tags.length > 0) {
      const problemTags = (p.tags || []).map(t => t.toLowerCase());
      if (!filters.tags.every(t => problemTags.includes(t))) return false;
    }
    if (filters.components && filters.components.length > 0) {
      if (!filters.components.includes(p.component)) return false;
    }
    return true;
  });
}

